    required this.pubkey,
    required this.createdAt,
    required this.kind,
    required this.tags,
    required this.content,
    required this.sig,
  });

  @override
  int get hashCode =>
      id.hashCode ^
      pubkey.hashCode ^
      createdAt.hashCode ^
      kind.hashCode ^
      tags.hashCode ^
      content.hashCode ^
      sig.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is SignedLocationEventFfi &&
          runtimeType == other.runtimeType &&
          id == other.id &&
          pubkey == other.pubkey &&
          createdAt == other.createdAt &&
          kind == other.kind &&
          tags == other.tags &&
          content == other.content &&
          sig == other.sig;
}

/// What an M8-4 subscription-health tick did (FFI mirror of
/// [`haven_core::relay::live_sync::HealthAction`]).
///
/// Fieldless / payload-free — no url, id, or hex — so it is leak-free by
/// construction (Security Rule 4/6).
enum SubscriptionHealthActionFfi {
  /// No live engine session — the inert no-op that ships while the live-sync
  /// engine is off (`liveSyncEnabled == false`).
  engineOff,

  /// The engine is running and every relay is connected — nothing to do.
  healthy,

  /// A relay had dropped; every subscription was re-anchored at its cursor.
  resubscribed,
}

/// Presence-only result of an M8-4 subscription-health maintenance tick.
///
/// Counters + an action enum only — never a relay url, group id, or pubkey — so
/// it is leak-free (Security Rule 4/6). This is the shape the Dart
/// `MaintenanceScheduler` folds ticks into.
class SubscriptionHealthOutcomeFfi {
  /// What the tick did.
  final SubscriptionHealthActionFfi action;

  /// Relays in the engine pool at check time (`0` when engine off).
  final int relaysTotal;

  /// Relays still coming up at check time (`Initialized` / `Pending` /
  /// `Connecting`); `0` when engine off. Reported so a caller can tell "all
  /// healthy" from "some still connecting" — a transient state that never
  /// triggers a resubscribe.
  final int relaysStillConnecting;

  /// Relays found dropped at check time (`0` when engine off).
  final int relaysDisconnected;

  const SubscriptionHealthOutcomeFfi({
    required this.action,
    required this.relaysTotal,
    required this.relaysStillConnecting,
    required this.relaysDisconnected,
  });

  @override
  int get hashCode =>
      action.hashCode ^
      relaysTotal.hashCode ^
      relaysStillConnecting.hashCode ^
      relaysDisconnected.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is SubscriptionHealthOutcomeFfi &&
          runtimeType == other.runtimeType &&
          action == other.action &&
          relaysTotal == other.relaysTotal &&
          relaysStillConnecting == other.relaysStillConnecting &&
          relaysDisconnected == other.relaysDisconnected;
}

/// A cached tile and its conditional-revalidation metadata, for Dart.
///
/// `bytes` is public map imagery (encrypted only at rest), so it is surfaced
/// directly. No coordinates are carried, and there is intentionally no `Debug`
/// impl that prints `bytes`.
class TileCacheEntryFfi {
  /// Raw tile bytes (PNG).
  final Uint8List bytes;

  /// HTTP freshness deadline in unix milliseconds.
  final PlatformInt64 staleAtMs;

  /// `Last-Modified` as unix milliseconds, if present.
  final PlatformInt64? lastModifiedMs;

  /// `ETag` value, if present.
  final String? etag;

  const TileCacheEntryFfi({
    required this.bytes,
    required this.staleAtMs,
    this.lastModifiedMs,
    this.etag,
  });

  @override
  int get hashCode =>
      bytes.hashCode ^
      staleAtMs.hashCode ^
      lastModifiedMs.hashCode ^
      etag.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is TileCacheEntryFfi &&
          runtimeType == other.runtimeType &&
          bytes == other.bytes &&
          staleAtMs == other.staleAtMs &&
          lastModifiedMs == other.lastModifiedMs &&
          etag == other.etag;
}

/// Unsigned location event (FFI wrapper for inner event kind 9).
///
/// This is the inner event containing location data before encryption.
/// It is wrapped in a kind 445 group message for transmission.
class UnsignedLocationEventFfi {
  /// Event kind (9 for location data per MIP-03).
  final int kind;

  /// JSON-serialized location data.
  final String content;

  /// Event tags (typically empty for inner events).
  final List<List<String>> tags;

  /// Unix timestamp when the event was created.
  final PlatformInt64 createdAt;

  const UnsignedLocationEventFfi({
    required this.kind,
    required this.content,
    required this.tags,
    required this.createdAt,
  });

  @override
  int get hashCode =>
      kind.hashCode ^ content.hashCode ^ tags.hashCode ^ createdAt.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is UnsignedLocationEventFfi &&
          runtimeType == other.runtimeType &&
          kind == other.kind &&
          content == other.content &&
          tags == other.tags &&
          createdAt == other.createdAt;
}
